var threeConsecutiveOdds = function(arr) {
    let streak = 0;
    for (const x of arr) {
        if (x % 2 !== 0) {
            streak++;
            if (streak === 3) return true;
        } else {
            streak = 0;
        }
    }
    return false;
};
